// Import polyfills to avoid 'Console is not a constructor' error

// REMOVED console-polyfill import which may be causing issues

// Import core-js for comprehensive polyfills
import 'core-js/stable';
// Import fetch polyfill
import 'whatwg-fetch';

// This file contains polyfills for browser compatibility

// Declare missing types for window properties
declare global {
  interface Window {
    Console?: any;
    Buffer?: any;
    process?: any;
    __consoleLoadingPrevented?: boolean;
  }
}

// Protect against Console constructor error - with more protection
if (typeof window !== 'undefined') {
  try {
    // More aggressive protection
    delete window.Console;
    Object.defineProperty(window, 'Console', {
      configurable: true,
      get: function() {
        console.warn('Blocked Console constructor access from polyfills.ts');
        return null;
      },
      set: function() {
        // Prevent setting Console
        return;
      }
    });
    
    // Also make sure console methods are safe
    const originalConsole = window.console || {};
    const methods = ['log', 'error', 'warn', 'info', 'debug', 'trace', 'dir', 'table'];
    
    methods.forEach(method => {
      if (typeof (originalConsole as any)[method] !== 'function') {
        (originalConsole as any)[method] = function() {};
      }
    });
    
    // Ensure console is not replaced with something unsafe
    Object.defineProperty(window, 'console', {
      configurable: true,
      get: function() {
        return originalConsole;
      },
      set: function(value: any) {
        console.warn('Attempted to replace console object - prevented');
        Object.keys(value).forEach(key => {
          if (typeof value[key] === 'function') {
            (originalConsole as any)[key] = value[key];
          }
        });
        return originalConsole;
      }
    });
  } catch (e) {
    console.error('Error setting up console protection:', e);
  }
}

// Add Buffer if not available
if (typeof window !== 'undefined' && !window.Buffer) {
  try {
    window.Buffer = require('buffer/').Buffer;
  } catch (e) {
    console.error('Failed to load Buffer polyfill:', e);
  }
}

// Add process if not available
if (typeof window !== 'undefined' && !window.process) {
  try {
    window.process = require('process/browser');
  } catch (e) {
    console.error('Failed to load process polyfill:', e);
  }
}

// Polyfill for WebSocket
if (typeof window !== 'undefined' && !window.WebSocket) {
  console.warn('WebSocket API is not available in this browser.');
}

// Polyfill for fetch if not available
if (typeof window !== 'undefined' && !window.fetch) {
  console.warn('Fetch API is not available in this browser.');
  // Note: whatwg-fetch should already handle this
}

// Add crypto polyfills
if (typeof window !== 'undefined' && !window.crypto) {
  try {
    // This is a very simplified version - not secure for production use
    console.warn('Crypto API is not available. Using a fallback implementation.');
    
    // Using any to bypass the strict TypeScript check
    // In a production environment, a proper polyfill library should be used
    const cryptoPolyfill = {
      getRandomValues: function(array: any) {
        for (let i = 0; i < array.length; i++) {
          array[i] = Math.floor(Math.random() * 256);
        }
        return array;
      }
    };
    
    // @ts-ignore - Bypassing type checking for the polyfill
    window.crypto = cryptoPolyfill;
  } catch (e) {
    console.error('Failed to provide crypto polyfill:', e);
  }
}

// Check and report environment
export const checkEnvironment = () => {
  if (typeof window === 'undefined') {
    return { isServer: true, isClient: false, apis: {} };
  }

  const apis = {
    fetch: typeof window.fetch !== 'undefined',
    WebSocket: typeof window.WebSocket !== 'undefined',
    localStorage: (() => {
      try {
        localStorage.setItem('test', 'test');
        localStorage.removeItem('test');
        return true;
      } catch (e) {
        return false;
      }
    })(),
    crypto: typeof window.crypto !== 'undefined',
    Buffer: typeof window.Buffer !== 'undefined',
    process: typeof window.process !== 'undefined',
    console: typeof window.console !== 'undefined'
  };

  return {
    isServer: false,
    isClient: true,
    apis,
    userAgent: navigator.userAgent
  };
};

// Export a default function for importing in index.tsx
export default function setupPolyfills() {
  const env = checkEnvironment();
  console.log('Environment check:', env);
  
  // Additional early-init debugging
  if (typeof window !== 'undefined') {
    console.log('Console constructor prevented:', window.Console === null || window.Console === undefined);
    console.log('Require interception active:', typeof window.__consoleLoadingPrevented !== 'undefined');
  }
  
  return env;
} 