import React, { useState } from 'react';
import { ThemeProvider as MuiThemeProvider, createTheme } from '@mui/material/styles';
import CssBaseline from '@mui/material/CssBaseline';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Box, useMediaQuery } from '@mui/material';
import { useTheme } from './context/ThemeContext';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import Dashboard from './components/Dashboard';
import './styles/App.css';

const App: React.FC = () => {
  const { darkMode } = useTheme();
  const isMobile = useMediaQuery('(max-width:768px)');
  const [mobileOpen, setMobileOpen] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  
  // Handle mobile drawer toggle
  const handleDrawerToggle = () => {
    setMobileOpen(!mobileOpen);
  };

  const handleDrawerClose = () => {
    setMobileOpen(false);
  };

  const handleSidebarToggle = () => {
    setSidebarOpen(!sidebarOpen);
  };

  // Create MUI theme based on dark mode state
  const theme = createTheme({
    palette: {
      mode: darkMode ? 'dark' : 'light',
      primary: {
        main: '#1976d2', // Blue
      },
      secondary: {
        main: '#2e7d32', // Green
      },
      background: {
        default: darkMode ? '#121212' : '#FFFFFF',
        paper: darkMode ? '#1e1e1e' : '#FFFFFF',
      },
      text: {
        primary: darkMode ? '#FFFFFF' : '#000000',
        secondary: darkMode ? '#808080' : '#E0E0E0',
      },
      divider: darkMode ? 'rgba(255, 255, 255, 0.12)' : 'rgba(0, 0, 0, 0.12)',
    },
    typography: {
      fontFamily: '"Inter", "Roboto", "Helvetica", "Arial", sans-serif',
    },
    components: {
      MuiPaper: {
        styleOverrides: {
          root: {
            boxShadow: '0px 4px 8px rgba(0, 0, 0, 0.1)',
            transition: 'box-shadow 0.3s ease-in-out',
            '&:hover': {
              boxShadow: '0px 8px 16px rgba(0, 0, 0, 0.2)',
            },
          },
        },
      },
      MuiButton: {
        styleOverrides: {
          root: {
            borderRadius: 8,
            padding: '8px 16px',
            transition: 'all 0.3s ease-in-out',
            boxShadow: '0px 4px 8px rgba(0, 0, 0, 0.1)',
            '&:hover': {
              boxShadow: '0px 8px 16px rgba(0, 0, 0, 0.2)',
              transform: 'translateY(-2px)',
            },
          },
        },
      },
      MuiCard: {
        styleOverrides: {
          root: {
            boxShadow: '0px 4px 8px rgba(0, 0, 0, 0.1)',
            transition: 'all 0.3s ease-in-out',
            '&:hover': {
              boxShadow: '0px 8px 16px rgba(0, 0, 0, 0.2)',
            },
          },
        },
      },
      MuiAppBar: {
        styleOverrides: {
          root: {
            boxShadow: '0px 4px 8px rgba(0, 0, 0, 0.1)',
          },
        },
      },
      MuiDrawer: {
        styleOverrides: {
          paper: {
            boxShadow: '0px 4px 8px rgba(0, 0, 0, 0.1)',
          },
        },
      },
      MuiListItem: {
        styleOverrides: {
          root: {
            transition: 'background-color 0.3s ease-in-out',
          },
        },
      },
      MuiCssBaseline: {
        styleOverrides: {
          body: {
            transition: 'background-color 0.3s ease-in-out',
          },
          '*': {
            padding: '0',
            margin: '0',
            boxSizing: 'border-box',
          },
          '.MuiContainer-root, .MuiGrid-container': {
            padding: '16px 24px',
          },
        },
      },
    },
    spacing: 8,
  });

  const drawerWidth = sidebarOpen ? 280 : 72;

  return (
    <Router>
      <MuiThemeProvider theme={theme}>
        <CssBaseline />
        <Box className={`app-container ${darkMode ? 'dark' : 'light'}`}>
          <Header 
            onMenuClick={handleDrawerToggle} 
            sidebarOpen={sidebarOpen}
            onSidebarToggle={handleSidebarToggle}
          />
          <Box className="content-wrapper">
            <Sidebar 
              mobileOpen={mobileOpen} 
              onMobileClose={handleDrawerClose}
              isOpen={sidebarOpen}
              onToggle={handleSidebarToggle}
            />
            <Box 
              component="main" 
              className="main-content"
              sx={{ 
                flexGrow: 1, 
                p: 3, 
                pt: 2,
                width: { sm: `calc(100% - ${isMobile ? 0 : drawerWidth}px)` },
                ml: { sm: isMobile ? 0 : 0 },
                pl: { xs: 2, sm: 2 },
                transition: theme.transitions.create(['margin', 'width'], {
                  easing: theme.transitions.easing.sharp,
                  duration: theme.transitions.duration.enteringScreen,
                }),
              }}
            >
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/chat" element={<ChatWindow />} />
                <Route path="/settings" element={<div>Settings Page (Coming Soon)</div>} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </Box>
          </Box>
        </Box>
      </MuiThemeProvider>
    </Router>
  );
};

export default App;
