import React, { useState, useRef, useEffect } from 'react';
import { Box, Typography, Paper, Avatar, TextField, Button, Tooltip, useTheme, IconButton, Divider } from '@mui/material';
import SendIcon from '@mui/icons-material/Send';
import SmartToyIcon from '@mui/icons-material/SmartToy';
import PersonIcon from '@mui/icons-material/Person';
import AttachmentIcon from '@mui/icons-material/Attachment';
import MicIcon from '@mui/icons-material/Mic';

// Define message type
interface Message {
  id: string;
  content: string;
  sender: 'user' | 'bot';
  timestamp: Date;
}

const ChatWindow: React.FC = () => {
  const theme = useTheme();
  const [inputValue, setInputValue] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    {
      id: '1',
      content: 'Hello! I\'m your financial assistant. I can help you analyze market trends, check crypto prices, and answer questions about your investments. How can I help you today?',
      sender: 'bot',
      timestamp: new Date()
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Scroll to bottom when messages change
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const handleSendMessage = () => {
    if (inputValue.trim() === '') return;

    // Add user message
    const userMessage: Message = {
      id: Date.now().toString(),
      content: inputValue,
      sender: 'user',
      timestamp: new Date()
    };
    
    setMessages(prev => [...prev, userMessage]);
    setInputValue('');

    // Focus input after sending
    setTimeout(() => {
      inputRef.current?.focus();
    }, 50);

    // Simulate bot response (in a real app, this would call an API)
    simulateBotResponse(inputValue);
  };

  const simulateBotResponse = (userInput: string) => {
    // Wait 1 second before responding
    setTimeout(() => {
      let botResponse = '';
      
      // Simple keyword matching for demo purposes
      const input = userInput.toLowerCase();
      if (input.includes('bitcoin') || input.includes('btc') || input.includes('crypto')) {
        botResponse = 'Bitcoin (BTC) is currently trading at approximately $62,500. It has seen a 3.2% increase in the last 24 hours with a market capitalization of $1.23 trillion.';
      } else if (input.includes('stock') || input.includes('market')) {
        botResponse = 'The stock market has been showing mixed signals today. The S&P 500 is up 0.5%, while the Nasdaq has seen a slight decrease of 0.2%. Tech stocks are generally performing well.';
      } else if (input.includes('invest') || input.includes('portfolio')) {
        botResponse = 'Based on your investment profile, I recommend a diversified portfolio with approximately 60% stocks, 20% bonds, 10% cryptocurrencies, and 10% cash or cash equivalents.';
      } else {
        botResponse = 'I understand you\'re asking about financial information. Could you provide more specific details about what you\'d like to know?';
      }
      
      const botMessage: Message = {
        id: Date.now().toString(),
        content: botResponse,
        sender: 'bot',
        timestamp: new Date()
      };
      
      setMessages(prev => [...prev, botMessage]);
    }, 1000);
  };

  const formatTimestamp = (date: Date) => {
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <Box sx={{ 
      height: '100%', 
      display: 'flex', 
      flexDirection: 'column', 
      width: '100%',
    }}>
      <Box sx={{ 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'space-between',
        mb: { xs: 1, sm: 1.5 },
        minHeight: 32
      }}>
        <Box sx={{ display: 'flex', alignItems: 'center' }}>
          <SmartToyIcon sx={{ mr: 0.75, fontSize: '1.25rem' }} color="primary" />
          <Typography 
            variant="subtitle1" 
            component="h2" 
            fontWeight="600" 
            sx={{ 
              fontSize: { xs: '0.9rem', sm: '1rem' },
              overflow: 'hidden',
              textOverflow: 'ellipsis',
              whiteSpace: 'nowrap'
            }}
          >
            AI Financial Assistant
          </Typography>
        </Box>
        <Typography
          variant="caption"
          color="text.secondary"
          sx={{ fontSize: '0.7rem' }}
        >
          Ask about investments, market trends, or financial advice
        </Typography>
      </Box>
      
      <Box 
        sx={{ 
          flexGrow: 1, 
          display: 'flex', 
          flexDirection: 'column',
          height: { xs: 'calc(100% - 90px)', md: 'calc(100% - 80px)' },
          borderRadius: 1,
          overflow: 'hidden',
          position: 'relative',
          width: '100%',
          border: `1px solid ${theme.palette.divider}`,
          bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.03)' : 'rgba(0,0,0,0.01)'
        }}
      >
        {/* Chat messages container */}
        <Box sx={{ 
          flex: 1, 
          overflowY: 'auto', 
          display: 'flex',
          flexDirection: 'column',
          gap: 1.5,
          p: 1.5,
          '&::-webkit-scrollbar': {
            width: '4px',
          },
          '&::-webkit-scrollbar-track': {
            background: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)',
          },
          '&::-webkit-scrollbar-thumb': {
            background: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)',
            borderRadius: '4px',
          },
        }}>
          {messages.map((message) => (
            <Box 
              key={message.id} 
              sx={{ 
                display: 'flex', 
                gap: 1, 
                alignItems: 'flex-start',
                justifyContent: message.sender === 'user' ? 'flex-end' : 'flex-start',
                maxWidth: '100%'
              }}
            >
              {message.sender === 'bot' && (
                <Avatar 
                  sx={{ 
                    bgcolor: 'primary.main', 
                    width: 28, 
                    height: 28 
                  }}
                >
                  <SmartToyIcon sx={{ fontSize: '0.9rem' }} />
                </Avatar>
              )}
              
              <Box 
                sx={{ 
                  maxWidth: '75%',
                  display: 'flex',
                  flexDirection: 'column'
                }}
              >
                <Paper sx={{ 
                  p: 1.5, 
                  bgcolor: message.sender === 'user' 
                    ? theme.palette.primary.main 
                    : theme.palette.mode === 'dark' 
                      ? 'rgba(255,255,255,0.05)' 
                      : 'rgba(0,0,0,0.02)', 
                  borderRadius: message.sender === 'user' 
                    ? '12px 4px 12px 12px' 
                    : '4px 12px 12px 12px',
                  color: message.sender === 'user' ? '#fff' : 'inherit',
                  boxShadow: message.sender === 'user'
                    ? '0px 2px 4px rgba(0,0,0,0.1)'
                    : '0px 1px 3px rgba(0,0,0,0.05)',
                }}>
                  <Typography variant="body2" sx={{ 
                    fontSize: '0.875rem', 
                    lineHeight: 1.4,
                    whiteSpace: 'pre-wrap',
                    wordBreak: 'break-word'
                  }}>
                    {message.content}
                  </Typography>
                </Paper>
                
                <Typography 
                  variant="caption" 
                  color="text.secondary" 
                  sx={{ 
                    fontSize: '0.7rem', 
                    mt: 0.5,
                    alignSelf: message.sender === 'user' ? 'flex-end' : 'flex-start'
                  }}
                >
                  {formatTimestamp(message.timestamp)}
                </Typography>
              </Box>
              
              {message.sender === 'user' && (
                <Avatar 
                  sx={{ 
                    bgcolor: 'secondary.main', 
                    width: 28, 
                    height: 28 
                  }}
                >
                  <PersonIcon sx={{ fontSize: '0.9rem' }} />
                </Avatar>
              )}
            </Box>
          ))}
          <div ref={messagesEndRef} />
        </Box>
        
        {/* Chat input area */}
        <Box sx={{ 
          display: 'flex', 
          gap: 1, 
          p: 1.5,
          borderTop: `1px solid ${theme.palette.divider}`,
          bgcolor: theme.palette.background.paper
        }}>
          <Box sx={{ display: 'flex', gap: 0.5 }}>
            <Tooltip title="Attach file">
              <IconButton size="small" sx={{ color: 'text.secondary' }}>
                <AttachmentIcon fontSize="small" />
              </IconButton>
            </Tooltip>
            <Tooltip title="Voice input">
              <IconButton size="small" sx={{ color: 'text.secondary' }}>
                <MicIcon fontSize="small" />
              </IconButton>
            </Tooltip>
          </Box>
          
          <TextField
            placeholder="Ask about your finances..."
            fullWidth
            variant="outlined"
            size="small"
            value={inputValue}
            onChange={handleInputChange}
            onKeyPress={handleKeyPress}
            inputRef={inputRef}
            multiline
            maxRows={3}
            sx={{ 
              '& .MuiOutlinedInput-root': {
                borderRadius: '20px',
                fontSize: '0.875rem',
              }
            }}
          />
          
          <Tooltip title="Send message">
            <Button 
              variant="contained" 
              color="primary"
              onClick={handleSendMessage}
              disabled={inputValue.trim() === ''}
              sx={{ 
                borderRadius: '50%', 
                minWidth: '40px',
                width: '40px',
                height: '40px',
                padding: 0,
                transition: 'all 0.3s ease-in-out',
                boxShadow: '0px 2px 5px rgba(0, 0, 0, 0.1)',
                '&:hover': {
                  boxShadow: '0px 4px 8px rgba(0, 0, 0, 0.2)',
                  transform: 'translateY(-2px)'
                }
              }}
            >
              <SendIcon sx={{ fontSize: '1.1rem' }} />
            </Button>
          </Tooltip>
        </Box>
      </Box>
      
      <Typography 
        variant="caption" 
        color="text.secondary" 
        align="center" 
        sx={{ 
          mt: 1, 
          fontSize: '0.7rem',
          display: 'block',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
          whiteSpace: 'nowrap'
        }}
      >
        Powered by AI for real-time financial insights
      </Typography>
    </Box>
  );
};

export default ChatWindow; 