/**
 * Get crypto news synchronously - no async issues
 */
export const getLatestNews = (limit: number = 10): NewsItem[] => {
  console.log('cryptoNewsService.getLatestNews: Returning static data immediately');
  
  // Create fresh timestamps
  const freshNews = CRYPTO_NEWS.map((item, index) => ({
    ...item,
    publishedAt: new Date(Date.now() - (index * 30 + Math.random() * 30) * 60000).toISOString()
  }));
  
  return freshNews.slice(0, limit);
};

/**
 * Subscribe to news updates with periodic polling
 */
export const subscribeToNewsUpdates = (
  callback: (news: NewsItem[]) => void,
  interval: number = 60000
): () => void => {
  console.log('cryptoNewsService.subscribeToNewsUpdates: Setting up news subscription');
  
  // Call immediately with static data
  callback(getLatestNews(10));
  
  // Set up interval for refreshes
  const intervalId = setInterval(() => {
    console.log('cryptoNewsService.subscribeToNewsUpdates: Refreshing news data');
    callback(getLatestNews(10));
  }, interval);
  
  // Return cleanup function
  return () => {
    console.log('cryptoNewsService.subscribeToNewsUpdates: Cleaning up subscription');
    clearInterval(intervalId);
  };
}; 