import React, { useState, useEffect, useRef } from 'react';
import { 
  Box, 
  Typography, 
  Paper, 
  Grid, 
  CircularProgress,
  Avatar,
  Chip,
  Tooltip,
  useTheme,
  useMediaQuery,
  IconButton,
  Fade,
  LinearProgress
} from '@mui/material';
import ArrowDropUpIcon from '@mui/icons-material/ArrowDropUp';
import ArrowDropDownIcon from '@mui/icons-material/ArrowDropDown';
import UpdateIcon from '@mui/icons-material/Update';
import RefreshIcon from '@mui/icons-material/Refresh';
import TrendingUpIcon from '@mui/icons-material/TrendingUp';
import TrendingDownIcon from '@mui/icons-material/TrendingDown';
import { getTickerData, CryptoData, subscribeToTickerUpdates } from '../services/coinGeckoService';

const formatPrice = (price: number): string => {
  if (price >= 1000) {
    return price.toLocaleString('en-US', { 
      style: 'currency', 
      currency: 'USD',
      maximumFractionDigits: 0
    });
  } else if (price >= 1) {
    return price.toLocaleString('en-US', { 
      style: 'currency', 
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    });
  } else {
    // Show more decimals for small amounts
    return price.toLocaleString('en-US', { 
      style: 'currency', 
      currency: 'USD',
      minimumFractionDigits: 4,
      maximumFractionDigits: 6
    });
  }
};

const formatTimeAgo = (dateString?: string): string => {
  if (!dateString) return 'Unknown';
  
  const now = new Date();
  const updateTime = new Date(dateString);
  const diffSeconds = Math.floor((now.getTime() - updateTime.getTime()) / 1000);
  
  if (diffSeconds < 5) return 'Just now';
  if (diffSeconds < 60) return `${diffSeconds}s ago`;
  if (diffSeconds < 3600) return `${Math.floor(diffSeconds / 60)}m ago`;
  return `${Math.floor(diffSeconds / 3600)}h ago`;
};

// Add interface for component props
interface CryptoMarketViewProps {
  coinLimit?: number;
}

const CryptoMarketView: React.FC<CryptoMarketViewProps> = ({ coinLimit = 10 }) => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('sm'));
  const isTablet = useMediaQuery(theme.breakpoints.down('md'));
  const [cryptoData, setCryptoData] = useState<CryptoData[]>([]);
  const [previousData, setPreviousData] = useState<Record<string, number>>({});
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [refreshing, setRefreshing] = useState<boolean>(false);
  const dataRef = useRef<CryptoData[]>([]);
  const isMounted = useRef(true);
  const priceUpdated = useRef<Record<string, boolean>>({});

  useEffect(() => {
    let isMounted = true;
    
    const fetchCryptoData = async () => {
      try {
        setLoading(true);
        const data = await getTickerData();
        if (isMounted) {
          // Store previous prices to detect changes
          const priceMap: Record<string, number> = {};
          cryptoData.forEach(crypto => {
            priceMap[crypto.symbol] = crypto.price;
          });
          setPreviousData(priceMap);
          
          setCryptoData(data);
          setLastUpdated(new Date());
          setError(null);
          dataRef.current = data;
        }
      } catch (err) {
        console.error('Failed to fetch crypto data:', err);
        if (isMounted) {
          setError('Failed to load cryptocurrency data');
        }
      } finally {
        if (isMounted) {
          setLoading(false);
        }
      }
    };

    fetchCryptoData();

    // Track supported cryptocurrencies with more comprehensive list
    const supportedCryptos = [
      "BTC", "ETH", "XRP", "SOL", "ADA", "DOT", "AVAX", "DOGE", 
      "MATIC", "LINK", "UNI", "ATOM", "LTC", "ALGO"
    ];

    // Set up real-time updates
    const cleanupSubscription = subscribeToTickerUpdates(
      supportedCryptos, 
      (updatedData) => {
        if (isMounted) {
          // Store previous prices to detect changes
          const priceMap: Record<string, number> = {};
          cryptoData.forEach(crypto => {
            priceMap[crypto.symbol] = crypto.price;
          });
          setPreviousData(priceMap);
          
          // Flag prices that changed for animation
          const updatedFlags: Record<string, boolean> = {};
          updatedData.forEach(crypto => {
            if (priceMap[crypto.symbol] && priceMap[crypto.symbol] !== crypto.price) {
              updatedFlags[crypto.symbol] = true;
              
              // Reset the flag after animation duration
              setTimeout(() => {
                if (isMounted) {
                  priceUpdated.current = {
                    ...priceUpdated.current,
                    [crypto.symbol]: false
                  };
                }
              }, 1000);
            }
          });
          
          priceUpdated.current = updatedFlags;
          setCryptoData(updatedData);
          dataRef.current = updatedData;
          setLastUpdated(new Date());
        }
      }
    );

    // Implement data refresh every 30 seconds as a backup
    const refreshInterval = setInterval(() => {
      if (isMounted) {
        fetchCryptoData();
      }
    }, 30000);

    return () => {
      isMounted = false;
      cleanupSubscription();
      clearInterval(refreshInterval);
    };
  }, []);

  // If there's no data yet but we're not loading, use backup data
  useEffect(() => {
    if (!loading && cryptoData.length === 0 && dataRef.current.length > 0) {
      setCryptoData(dataRef.current);
    }
  }, [loading, cryptoData]);

  // Format the exact price for tooltip
  const getExactPrice = (price: number): string => {
    return price.toLocaleString('en-US', { 
      style: 'currency', 
      currency: 'USD',
      minimumFractionDigits: 2,
      maximumFractionDigits: 8
    });
  };

  // Format percent change
  const formatPercentChange = (change: number): string => {
    return `${change >= 0 ? '+' : ''}${change.toFixed(2)}%`;
  };

  // Format the last updated time
  const formatLastUpdated = (date: Date): string => {
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffSecs = Math.floor(diffMs / 1000);
    
    if (diffSecs < 60) {
      return `${diffSecs}s ago`;
    } else if (diffSecs < 3600) {
      return `${Math.floor(diffSecs / 60)}m ago`;
    } else {
      return date.toLocaleTimeString();
    }
  };

  // Format market cap in a readable way
  const formatMarketCap = (marketCap?: number): string => {
    if (!marketCap) return 'N/A';
    
    if (marketCap >= 1000000000) {
      return `$${(marketCap / 1000000000).toFixed(1)}B`;
    } else if (marketCap >= 1000000) {
      return `$${(marketCap / 1000000).toFixed(1)}M`;
    } else {
      return `$${(marketCap / 1000).toFixed(1)}K`;
    }
  };

  // Determine if a price has increased or decreased from previous data
  const getPriceChangeDirection = (symbol: string, currentPrice: number): 'up' | 'down' | 'none' => {
    const previousPrice = previousData[symbol];
    if (!previousPrice) return 'none';
    
    if (currentPrice > previousPrice) return 'up';
    if (currentPrice < previousPrice) return 'down';
    return 'none';
  };

  // Handle refresh button click
  const handleRefresh = async () => {
    try {
      setRefreshing(true);
      const data = await getTickerData();
      if (isMounted.current) {
        // Store previous prices to detect changes
        const priceMap: Record<string, number> = {};
        cryptoData.forEach(crypto => {
          priceMap[crypto.symbol] = crypto.price;
        });
        setPreviousData(priceMap);
        
        setCryptoData(data);
        dataRef.current = data;
        setLastUpdated(new Date());
        setError(null);
      }
    } catch (err) {
      if (isMounted.current) {
        setError('Failed to fetch crypto data');
        console.error(err);
      }
    } finally {
      if (isMounted.current) {
        setRefreshing(false);
      }
    }
  };

  if (loading && cryptoData.length === 0) {
    return (
      <Paper 
        elevation={3} 
        sx={{ 
          p: 3, 
          height: '100%',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center'
        }}
      >
        <CircularProgress size={40} />
        <Typography variant="body1" sx={{ mt: 2 }}>
          Loading cryptocurrency data...
        </Typography>
      </Paper>
    );
  }

  if (error && cryptoData.length === 0) {
    return (
      <Paper 
        elevation={3} 
        sx={{ 
          p: 3, 
          height: '100%',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center'
        }}
      >
        <Typography variant="body1" color="error">
          {error}
        </Typography>
      </Paper>
    );
  }

  return (
    <Paper 
      elevation={3} 
      sx={{ 
        p: { xs: 2, sm: 2.5 }, 
        height: '100%',
        width: '100%',
        display: 'flex',
        flexDirection: 'column',
        overflow: 'hidden',
        borderRadius: '10px',
        boxShadow: '0 4px 8px rgba(0, 0, 0, 0.15)',
        transition: 'all 0.3s ease',
        '&:hover': {
          transform: 'translateY(-3px)',
          boxShadow: '0 6px 12px rgba(0, 0, 0, 0.2)',
        }
      }}
    >
      <Box sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        mb: 1.5,
        flexWrap: 'wrap'
      }}>
        <Typography variant="subtitle1" fontWeight="600" sx={{ mr: 1 }}>
          Crypto Market
        </Typography>
        {lastUpdated && (
          <Box sx={{ display: 'flex', alignItems: 'center' }}>
            <Tooltip title={`Last data update: ${lastUpdated.toLocaleTimeString()}`}>
              <Box sx={{ 
                display: 'flex', 
                alignItems: 'center', 
                color: 'text.secondary',
                mr: 1
              }}>
                <UpdateIcon fontSize="small" sx={{ mr: 0.5, fontSize: '0.9rem' }} />
                <Typography variant="caption" noWrap>
                  {formatTimeAgo(lastUpdated.toISOString())}
                </Typography>
              </Box>
            </Tooltip>
            
            <Tooltip title="Refresh data">
              <IconButton 
                onClick={handleRefresh} 
                size="small"
                disabled={refreshing}
                sx={{ p: 0.5 }}
              >
                <RefreshIcon fontSize="small" />
              </IconButton>
            </Tooltip>
          </Box>
        )}
      </Box>
      
      {refreshing && (
        <LinearProgress sx={{ mb: 1, borderRadius: 1 }} />
      )}
      
      {/* Horizontal coin display */}
      <Box sx={{ 
        flex: 1, 
        overflowX: 'auto',
        overflowY: 'hidden',
        '&::-webkit-scrollbar': {
          height: '4px',
        },
        '&::-webkit-scrollbar-track': {
          background: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.05)',
        },
        '&::-webkit-scrollbar-thumb': {
          background: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)',
          borderRadius: '4px',
        }
      }}>
        <Box sx={{ 
          display: 'flex', 
          flexDirection: 'row',
          minWidth: 'fit-content',
          height: '100%'
        }}>
          {cryptoData.slice(0, coinLimit).map((crypto, index) => {
            const priceDirection = getPriceChangeDirection(crypto.symbol, crypto.price);
            const isPriceUpdated = priceUpdated.current[crypto.symbol];
            
            return (
              <Box 
                key={crypto.symbol}
                sx={{ 
                  display: 'flex', 
                  flexDirection: 'column',
                  justifyContent: 'center',
                  p: 1.5,
                  minWidth: '140px',
                  height: '100%',
                  borderRight: index < Math.min(cryptoData.length, coinLimit) - 1 ? `1px solid ${theme.palette.divider}` : 'none',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    bgcolor: theme.palette.mode === 'dark' ? 'rgba(255,255,255,0.05)' : 'rgba(0,0,0,0.02)',
                    borderRadius: 1,
                    transform: 'translateY(-2px)'
                  }
                }}
              >
                <Box sx={{ 
                  display: 'flex', 
                  alignItems: 'center',
                  mb: 1
                }}>
                  {crypto.logoUrl && (
                    <Avatar 
                      src={crypto.logoUrl} 
                      alt={crypto.name}
                      sx={{ width: 24, height: 24, mr: 1, flexShrink: 0 }}
                    />
                  )}
                  <Box>
                    <Typography 
                      variant="body2" 
                      fontWeight="500"
                      sx={{ 
                        textOverflow: 'ellipsis',
                        overflow: 'hidden',
                        whiteSpace: 'nowrap',
                        lineHeight: 1.2
                      }}
                    >
                      {crypto.symbol.toUpperCase()}
                    </Typography>
                    <Tooltip title={crypto.name}>
                      <Typography 
                        variant="caption" 
                        color="text.secondary"
                        sx={{ 
                          textOverflow: 'ellipsis',
                          overflow: 'hidden',
                          whiteSpace: 'nowrap',
                          display: 'block',
                          fontSize: '0.7rem'
                        }}
                      >
                        {crypto.name}
                      </Typography>
                    </Tooltip>
                  </Box>
                </Box>
                
                <Box sx={{ 
                  display: 'flex', 
                  flexDirection: 'column',
                  alignItems: 'center',
                  mb: 0.5
                }}>
                  <Tooltip title={getExactPrice(crypto.price)}>
                    <Typography 
                      variant="body2" 
                      fontWeight="500"
                      sx={{
                        textAlign: 'center',
                        fontFamily: 'monospace',
                        letterSpacing: '-0.5px',
                        transition: 'color 0.5s ease',
                        color: isPriceUpdated 
                          ? (priceDirection === 'up' ? 'success.main' : priceDirection === 'down' ? 'error.main' : 'inherit')
                          : 'inherit',
                        fontWeight: isPriceUpdated ? '700' : '500'
                      }}
                    >
                      {formatPrice(crypto.price)}
                    </Typography>
                  </Tooltip>
                  {crypto.marketCap && (
                    <Typography 
                      variant="caption" 
                      color="text.secondary"
                      sx={{ 
                        textOverflow: 'ellipsis',
                        overflow: 'hidden',
                        whiteSpace: 'nowrap',
                        fontSize: '0.7rem'
                      }}
                    >
                      MCap: {formatMarketCap(crypto.marketCap)}
                    </Typography>
                  )}
                </Box>
                
                <Box sx={{ display: 'flex', justifyContent: 'center', width: '100%' }}>
                  <Chip
                    icon={crypto.priceChangePercent >= 0 ? 
                      <TrendingUpIcon fontSize="small" /> : 
                      <TrendingDownIcon fontSize="small" />
                    }
                    label={formatPercentChange(crypto.priceChangePercent)}
                    size="small"
                    color={crypto.priceChangePercent >= 0 ? 'success' : 'error'}
                    variant="outlined"
                    sx={{ 
                      borderRadius: '4px',
                      height: 24,
                      fontSize: '0.7rem',
                      '& .MuiChip-icon': {
                        fontSize: '0.85rem',
                        ml: '4px',
                        mr: '-2px'
                      }
                    }}
                  />
                </Box>
              </Box>
            );
          })}
        </Box>
      </Box>
      
      <Box sx={{ 
        mt: 1.5, 
        borderTop: `1px solid ${theme.palette.divider}`,
        pt: 1 
      }}>
        <Typography 
          variant="caption" 
          color="text.secondary"
          sx={{
            display: 'block',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
            fontSize: '0.7rem',
            textAlign: 'center'
          }}
        >
          Real-time data with 3-second updates
        </Typography>
      </Box>
    </Paper>
  );
};

export default CryptoMarketView; 