// Import polyfills
import setupPolyfills from './polyfills';

// Now the rest of the imports
import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';
import reportWebVitals from './reportWebVitals';
import { ThemeProvider } from './context/ThemeContext';

// Initialize polyfills
try {
  const envInfo = setupPolyfills();
  console.log('Browser environment:', envInfo);
} catch (error) {
  console.error('Error setting up polyfills:', error);
}

const root = ReactDOM.createRoot(
  document.getElementById('root') as HTMLElement
);

try {
  // Check if Console constructor issue is fixed
  if (window.Console !== null && typeof window.Console !== 'function') {
    console.error('Warning: Console is not properly patched!');
  }
  
  // Start the app
  root.render(
    <React.StrictMode>
      <ThemeProvider>
        <App />
      </ThemeProvider>
    </React.StrictMode>
  );
} catch (error) {
  console.error('Fatal error rendering app:', error);
  // Display error in DOM if available
  const rootElem = document.getElementById('root');
  if (rootElem) {
    rootElem.innerHTML = `
      <div style="padding: 20px; color: red; font-family: sans-serif;">
        <h2>Application Error</h2>
        <p>${error instanceof Error ? error.message : String(error)}</p>
        <p>Please check the console for more details.</p>
      </div>
    `;
  }
}

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
